import{_ as o,r as t,o as i,c as d,a as e,b as n,d as a,e as r}from"./app-25fa875f.js";const l="/blog/assets/wsl-centos-zip-cbf2e573.png",c={},u=e("h1",{id:"wsl-centos-8",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#wsl-centos-8","aria-hidden":"true"},"#"),n(" WSL: CentOS 8")],-1),p=e("p",null,"Created by : Mr Dk.",-1),h=e("p",null,"2021 / 09 / 09 10:46",-1),v=e("p",null,"Ningbo, Zhejiang, China",-1),m=e("hr",null,null,-1),g=e("h2",{id:"background",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#background","aria-hidden":"true"},"#"),n(" Background")],-1),b=e("em",null,"PolarDB",-1),_={href:"https://github.com/Apsara/PolarDB-for-PostgreSQL",target:"_blank",rel:"noopener noreferrer"},f=e("em",null,"Alibaba Linux",-1),k=e("p",null,[n("发现 CentOS 系列在 "),e("em",null,"Microsoft Store"),n(" 中并没有可以下载的 distribution。经过了解，网上说需要付费 (我咋连付费的都没发现)，要么就用开源版本手动安装。所以记录一次手动安装的过程。")],-1),S=e("h2",{id:"download-and-install",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#download-and-install","aria-hidden":"true"},"#"),n(" Download and Install")],-1),L={href:"https://github.com/mishamosher/CentOS-WSL",target:"_blank",rel:"noopener noreferrer"},w={href:"https://github.com/mishamosher/CentOS-WSL/releases",target:"_blank",rel:"noopener noreferrer"},x=r('<p><img src="'+l+`" alt="wsl-centos-zip"></p><p>双击 <code>CentOS8.exe</code> 即可开始安装并注册到 WSL 中。安装完毕后，再次双击 <code>CentOS8.exe</code>，就能以 root 用户登录进入系统。</p><h2 id="uninstall" tabindex="-1"><a class="header-anchor" href="#uninstall" aria-hidden="true">#</a> Uninstall</h2><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code><span class="token punctuation">.</span>\\CentOS8<span class="token punctuation">.</span>exe clean
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="add-new-user" tabindex="-1"><a class="header-anchor" href="#add-new-user" aria-hidden="true">#</a> Add New User</h2><p>一直用 root 用户进行操作终究是不太好。最好是能够创建一个可登录的个人用户，偶尔 <code>sudo</code> 才对。创建新用户并设置密码：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">useradd</span> mrdrivingduck
<span class="token function">passwd</span> mrdrivingduck
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>后续发现新用户执行 <code>sudo</code> 命令时会有报错：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>mrdrivingduck not in the sudoers file. This incident will be reported.
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>因此，还需要把新创建的用户加入到 <code>/etc/sudoers</code> 文件中。这个文件是只读的，所以暂时将这个文件的权限设置为可写，写完以后再重置回去：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">chmod</span> u+w /etc/sudoers
<span class="token function">sudo</span> <span class="token function">chmod</span> u-w /etc/sudoers
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>在上述两条命令的中间，<code>/etc/sudoers</code> 是可以被编辑的。在最后加上下面的任意一行：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>mrdrivingduck ALL=(ALL) ALL
%mrdrivingduck ALL=(ALL) ALL
mrdrivingduck ALL=(ALL) NOPASSWD: ALL
%mrdrivingduck ALL=(ALL) NOPASSWD: ALL
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>mrdrivingduck</code> 和 <code>%mrdrivingduck</code> 的区别是，是用户还是用户组；<code>NOPASSWD</code> 的含义为，执行 sudo 命令时是否需要输入密码。</p><p>接下来，可以把 CentOS 的默认登录用户直接设置为新用户：</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code><span class="token punctuation">.</span>\\CentOS8<span class="token punctuation">.</span>exe config <span class="token operator">--</span>default-user mrdrivingduck
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>通过 WSL 命令也可以看到，目前两个 distribution 都启动了：</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code><span class="token function">PS</span> C:\\Users\\mrdrivingduck&gt; wsl <span class="token operator">-</span>l <span class="token operator">-</span>v
  NAME            STATE           VERSION
<span class="token operator">*</span> Ubuntu-20<span class="token punctuation">.</span>04    Running         2
  CentOS8         Running         2
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="migration" tabindex="-1"><a class="header-anchor" href="#migration" aria-hidden="true">#</a> Migration</h2><p>很尴尬的一件事，刚才的 CentOS8 的文件夹解压在桌面了。想把它挪到 C 盘的某个位置去。所以先让 WSL 停止：</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code>wsl <span class="token operator">--</span>shutdown CentOS8
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,21),C={href:"https://github.com/DDoSolitary/LxRunOffline",target:"_blank",rel:"noopener noreferrer"},O={href:"https://chocolatey.org/",target:"_blank",rel:"noopener noreferrer"},A=r(`<div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code>lxrunoffline <span class="token function">move</span> <span class="token operator">-</span>n CentOS8 <span class="token operator">-</span>d &lt;dest_folder&gt;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>其中 <code>CentOS8</code> 可以替换为任意 distribution 的名称。</p><hr><h2 id="references" tabindex="-1"><a class="header-anchor" href="#references" aria-hidden="true">#</a> References</h2>`,4),W={href:"https://zhuanlan.zhihu.com/p/272735470",target:"_blank",rel:"noopener noreferrer"},N={href:"https://blog.csdn.net/sinat_36118270/article/details/62899093",target:"_blank",rel:"noopener noreferrer"},D={href:"https://stackoverflow.com/questions/64185560/where-are-the-files-inside-wsl2-physically-stored",target:"_blank",rel:"noopener noreferrer"},y={href:"https://www.cnblogs.com/microestc/articles/13042072.html",target:"_blank",rel:"noopener noreferrer"};function P(B,E){const s=t("ExternalLinkIcon");return i(),d("div",null,[u,p,h,v,m,g,e("p",null,[n("最近两天参加 "),b,n(),e("a",_,[n("开源"),a(s)]),n(" 相关的开发，需要配置一个 CentOS 的环境 (果然，离开公司就没有 "),f,n(" 可以用了)。手边只有一台 Surface 的我当然还是选择 WSL2 啦~")]),k,S,e("p",null,[n("首先可以在 GitHub 上 "),e("a",L,[n("CentOS-WSL"),a(s)]),n(" 项目的 "),e("a",w,[n("release"),a(s)]),n(" 中下载压缩包并解压。")]),x,e("p",null,[n("接下来，直接移动文件肯定是不对的。因为 WSL 并不知道虚拟机的新位置。根据 stackoverflow 上的一个回答，发现 GitHub 上有一个非官方的迁移工具 "),e("a",C,[n("LxRunOffline"),a(s)]),n("。使用 Windows 下的软件包管理工具 "),e("a",O,[n("Chocolatey"),a(s)]),n(" 安装后，直接使用以下命令就可以无缝完成迁移，体验非常不错：")]),A,e("p",null,[e("a",W,[n("ZhiHu - 在 Windows 10 上使用 WSL 安装 CentOS"),a(s)])]),e("p",null,[e("a",N,[n("CSDN - 解决 Linux 下 sudo 更改文件权限报错"),a(s)])]),e("p",null,[e("a",D,[n("stackoverflow - Where are the files inside wsl2 physically stored?"),a(s)])]),e("p",null,[e("a",y,[n("博客园 - WSL2 Linux 设置默认用户"),a(s)])])])}const V=o(c,[["render",P],["__file","WSL CentOS8.html.vue"]]);export{V as default};
